#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3000005;
int t,q,n,nxt[N][75],cnt[N],num;
string s;
int fun(char c)
{
	if(c>='A'&&c<='Z') return c-'A';
	if(c>='a'&&c<='z') return c-'a'+26;
	return c-'0'+52;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		for(int i=0;i<=num;i++)
		{
			cnt[i]=0;
			for(int j=0;j<=65;j++)
			{
				nxt[i][j]=0;
			}
		}
		num=0;
		cin>>n>>q;
		for(int i=1;i<=n;i++)
		{
			cin>>s;
			int now=0;
			for(int j=0;j<s.size();j++)
			{
				int tmp=fun(s[j]);
				if(nxt[now][tmp]==0) nxt[now][tmp]=++num;
				now=nxt[now][tmp];
				cnt[now]++;
			}
		}
		for(int i=1;i<=q;i++) 
		{
			cin>>s;
			int now=0;
			for(int j=0;j<s.size();j++)
			{
				int tmp=fun(s[j]);
				if(nxt[now][tmp]==0)
				{
					cout<<"0\n";
					goto end;
				}
				now=nxt[now][tmp];
			}
			cout<<cnt[now]<<'\n';
			end: ;
		}
	}
	return 0;
}
